// Split published-posts array into N items.
const posts = $('Get Published Posts').first().json.data.posts || [];
return posts.map(p => ({ json: p }));

// MOCK of platform insights API call per post.
// Real (per platform):
//   instagram: GET /{media_id}/insights?metric=impressions,reach,engagement,saved
//   facebook:  GET /{post_id}/insights?metric=post_impressions,post_reactions_like_total,...
//   linkedin:  GET /socialActions/{share_urn} + /organizationalEntityShareStatistics
//   twitter:   GET /tweets/{id} with tweet.fields=public_metrics
// Each returns different shapes — we normalize them here.

const items = $input.all();

return items.map(it => {
  const p = it.json;
  // Synthetic but plausible engagement (deterministic-ish per platform)
  const baseImpressions = 1000 + Math.floor(Math.random() * 9000);
  const reach = Math.floor(baseImpressions * (0.55 + Math.random() * 0.3));
  const likes = Math.floor(reach * (0.02 + Math.random() * 0.08));
  const comments = Math.floor(likes * (0.05 + Math.random() * 0.15));
  const saves = (p.platform === 'instagram') ? Math.floor(likes * (0.08 + Math.random() * 0.2)) : 0;
  const shares = Math.floor(likes * (0.03 + Math.random() * 0.1));
  const engagement_rate = Math.round(((likes + comments + saves + shares) / baseImpressions) * 10000) / 10000;

  return { json: {
    ...p,
    impressions: baseImpressions,
    reach: reach,
    likes: likes,
    comments: comments,
    saves: saves,
    shares: shares,
    engagement_rate: engagement_rate,
    fetched_at: new Date().toISOString()
  }};
});

// Combine all per-post metrics into one summary.
const items = $input.all();
const rows = items.map(i => i.json);

const totals = rows.reduce((acc, r) => {
  acc.impressions += r.impressions || 0;
  acc.reach += r.reach || 0;
  acc.likes += r.likes || 0;
  acc.comments += r.comments || 0;
  acc.saves += r.saves || 0;
  acc.shares += r.shares || 0;
  return acc;
}, { impressions: 0, reach: 0, likes: 0, comments: 0, saves: 0, shares: 0 });

const avgEng = rows.length > 0
  ? Math.round((rows.reduce((s, r) => s + (r.engagement_rate || 0), 0) / rows.length) * 10000) / 10000
  : 0;

return [{ json: {
  success: true,
  cron: 'collect_metrics',
  ran_at: new Date().toISOString(),
  posts_measured: rows.length,
  totals: totals,
  avg_engagement_rate: avgEng,
  per_post: rows.map(r => ({
    slot_id: r.slot_id,
    platform: r.platform,
    platform_post_id: r.platform_post_id,
    impressions: r.impressions,
    reach: r.reach,
    likes: r.likes,
    comments: r.comments,
    saves: r.saves,
    shares: r.shares,
    engagement_rate: r.engagement_rate
  }))
}}];
